import { resolve } from 'path';
import { readFileSync } from 'fs';
import { adaptMdxAdmonitions } from './mdx-admonitions-adapter.js';

it('renders with the correct text', () => {
  const filepath = resolve(__dirname, './fixtures/foo.mdx');
  const content = readFileSync(filepath, 'utf-8');
  const filepath2 = resolve(__dirname, './fixtures/foo2.mdx');
  const content2 = readFileSync(filepath2, 'utf-8');
  expect(adaptMdxAdmonitions(content)).toEqual(content2);
});
